<template><div><PageHeader eyebrow="ADMIN / CHAT" title="聊天治理" description="查看会话、删除消息、禁言用户和关闭会话"><el-button @click="load">刷新</el-button></PageHeader><div class="chat-admin-grid"><el-table :data="conversations" highlight-current-row @current-change="select" height="560"><el-table-column prop="id" label="会话 ID" min-width="170"/><el-table-column prop="title" label="标题"/><el-table-column prop="conversationType" label="类型"/><el-table-column label="操作" width="150"><template #default="{row}"><el-button size="small" type="warning" @click.stop="close(row)">关闭</el-button><el-button size="small" type="danger" @click.stop="disband(row)">解散</el-button></template></el-table-column></el-table><div><h3>会话消息</h3><el-table :data="messages" height="500"><el-table-column prop="senderId" label="发送者" min-width="150"/><el-table-column prop="content" label="内容"/><el-table-column label="操作" width="90"><template #default="{row}"><el-button text type="danger" @click="removeMessage(row)">删除</el-button></template></el-table-column></el-table></div></div></div></template>
<script setup>import { onMounted,ref } from 'vue';import { ElMessageBox } from 'element-plus';import PageHeader from '../../components/PageHeader.vue';import { chatApi } from '../../api/chat';const conversations=ref([]),messages=ref([]),selected=ref(null);async function load(){conversations.value=await chatApi.adminConversations({page:0,size:100})}async function select(row){if(!row)return;selected.value=row;messages.value=await chatApi.adminMessages(row.id,{page:0,size:100})}async function removeMessage(row){const {value}=await ElMessageBox.prompt('删除原因','删除消息');await chatApi.adminRemoveMessage(row.id,value);select(selected.value)}async function close(row){const {value}=await ElMessageBox.prompt('关闭原因','关闭会话');await chatApi.close(row.id,value);load()}async function disband(row){await ElMessageBox.confirm('确定解散该会话吗？');await chatApi.disband(row.id,'管理员解散');load()}onMounted(load)</script>
